import{_ as o,o as t,c as i,a2 as a}from"./chunks/framework.CKCxdkvf.js";const m=JSON.parse('{"title":"RFC-009 — Mission flight params + timeline navigator","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-009.md","filePath":"rfc/RFC-009.md"}'),s={name:"rfc/RFC-009.md"};function n(r,e,l,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="rfc-009-—-mission-flight-params-timeline-navigator" tabindex="-1">RFC-009 — Mission flight params + timeline navigator <a class="header-anchor" href="#rfc-009-—-mission-flight-params-timeline-navigator" aria-label="Permalink to &quot;RFC-009 — Mission flight params + timeline navigator&quot;">​</a></h1><blockquote><p>Status · Closed · closed by ADR-027 (2026-04-29) Date · 2026-04-29 TA anchor · §components/mission-data · §components/fly-screen · §components/missions-screen Related PRDs · PRD-003 (Mission Arc), PRD-004 (Mission Library) Related ADRs · ADR-006 (mission JSON), ADR-019 (ajv validation), ADR-020 (canonical mission schema), ADR-024 (mission URL sharing), ADR-026 (multi-destination) Why this is an RFC · The current mission JSON has language-neutral identity + dates + a single <code>delta_v</code> string. <code>/fly</code> synthesises trajectories from <code>transit_days</code> alone; <code>/missions</code> shows agency + year + first-line. The mission record is <strong>identity, not flight</strong>. Real per-mission flight realism — characteristic energy, target b-plane, periapsis altitude, orbit-insertion ∆v, MET-stamped events — lives elsewhere or doesn&#39;t exist in our data. This RFC asks: how do we encode it, validate it, surface it, and gracefully handle the missions where the data is sparse or unavailable?</p></blockquote><h2 id="the-question" tabindex="-1">The question <a class="header-anchor" href="#the-question" aria-label="Permalink to &quot;The question&quot;">​</a></h2><p>Three coupled problems:</p><ol><li><p><strong>Data shape.</strong> What flight parameters get added to the mission record? A standardised schema that covers C3, V∞, declination, target-arrival geometry, key burns, and a structured event timeline — without ballooning a 30-line file into a 300-line one.</p></li><li><p><strong>Sparse coverage.</strong> Curiosity (NASA, well-documented) has every parameter publicly released. Mars 3 (USSR, 1971) has fragmentary records. Mariner 4 has near-complete telemetry from JPL TR-32-740. Apollo 11 is the most-documented mission ever. How do we encode &quot;known&quot;, &quot;approximate&quot;, and &quot;unknown&quot; without rendering as nothing or as fake numbers?</p></li><li><p><strong>Surface.</strong> Where does this data show up? Three candidate surfaces:</p><ul><li><strong>/fly HUD</strong> — mission-specific readouts replacing the current generic <code>transit_days</code> synthesis.</li><li><strong>/missions detail panel</strong> — a new FLIGHT tab alongside GALLERY and LEARN.</li><li><strong>Timeline navigator at the top of /missions</strong> — a horizontal time scrubber spanning 1957–2030, missions plotted as dots, drag-to-scrub filters the cards below.</li></ul></li></ol><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h2><ul><li><strong>Curious learner</strong> clicks Curiosity → sees not just &quot;254-day transit&quot; but &quot;C3 = 11.2 km²/s², launched 35° declination, arrived at 6.0 km/s, 4.1 km/s orbit insertion ∆v before atmospheric entry.&quot; The numbers are real and traceable.</li><li><strong>STEM student</strong> compares Mariner 4 vs Curiosity flight params side by side via the library and notices the C3 difference reflects launcher capability, not just timing.</li><li><strong>Teacher</strong> uses the timeline navigator to scrub from 1962 → 2024 and watches how the gap between launches collapsed from one-mission-per-decade to one-per-year. The collapse is felt visually, not read in text.</li><li><strong>Contributor</strong> adds a new mission and the schema tells them exactly which fields are required and which can be omitted with a <code>data_quality</code> flag.</li><li><strong><code>/fly</code> realism</strong>: each mission&#39;s outbound arc is parameterised by <em>its</em> C3 + V∞ + arrival declination, not synthesised from <code>transit_days</code> alone — so two missions with the same start and end dates render visibly distinct trajectories when their target geometry differs.</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>Encode flight params per mission in a way that ajv can validate at PR.</li><li>Allow partial / unknown values without breaking the schema or showing fake data.</li><li>Surface params in <code>/fly</code> (HUD) and <code>/missions</code> (FLIGHT tab) — make them legible to non-experts.</li><li>Add a timeline navigator at the top of <code>/missions</code> that filters cards below.</li><li>No regression on the existing 28 mission cards or the existing <code>/fly</code> rendering.</li></ul><h2 id="constraints" tabindex="-1">Constraints <a class="header-anchor" href="#constraints" aria-label="Permalink to &quot;Constraints&quot;">​</a></h2><ul><li><strong>ADR-020</strong> locks the canonical mission schema. Extensions go through ADR-027 (this RFC&#39;s expected closure).</li><li><strong>ADR-019</strong> locks ajv validation on PR. Every new field must validate.</li><li><strong>ADR-017</strong> locks i18n architecture. Editorial content (event notes, anomaly descriptions) lives in locale overlays; flight params (numeric) live in the base file.</li><li><strong>CLAUDE.md</strong> locks no-localStorage, mobile-first, 44px touch targets. Timeline navigator must work on phones.</li><li><strong>Data-quality honesty</strong> (PA §promises). Unknown params must show as &quot;—&quot; or &quot;unknown&quot;, never as plausible-sounding fake numbers.</li><li>The current <code>delta_v</code> string (&quot;~6.1 km/s&quot;) is loadbearing for <code>/fly</code> — must remain readable through a backward-compat shim or a dual-key migration.</li></ul><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h2><h3 id="what-flight-params-to-encode" tabindex="-1">What flight params to encode <a class="header-anchor" href="#what-flight-params-to-encode" aria-label="Permalink to &quot;What flight params to encode&quot;">​</a></h3><p><strong>Option F-A — Minimum viable.</strong> Add only <code>c3_km2_s2</code>, <code>v_infinity_arrival_km_s</code>, <code>orbit_insertion_dv_km_s</code>, and a list of <code>events[]</code> with <code>met_days</code> + <code>type</code>. Keeps the schema small. Misses the geometry (declination, target periapsis) that distinguishes one Mars mission from another visually.</p><p><strong>Option F-B — Full launch + arrival + cruise + events.</strong> Six sub-objects: <code>launch</code> (C3, declination, mass), <code>cruise</code> (TCM count, dust storm encounters if any), <code>arrival</code> (V∞, b-plane radius, periapsis km, inclination, insertion ∆v), <code>events[]</code> (MET-stamped milestones with type + optional editorial note via i18n overlay), <code>descent</code> for landers, <code>return</code> for sample-return / crewed. Each sub-object is optional — missing = unknown. Maximum realism. Largest schema; most fields to fill per mission.</p><p><strong>Option F-C — Tiered: required, optional, advanced.</strong> Three tiers: (1) required for every mission (TLI/TMI ∆v, peak heliocentric speed, arrival geometry summary); (2) optional for well-documented missions (full F-B contents); (3) advanced for the STEM student (separate JSON file linked from the mission record). Keeps the base mission compact but lets a thorough mission carry full data.</p><h3 id="how-to-handle-sparse-data" tabindex="-1">How to handle sparse data <a class="header-anchor" href="#how-to-handle-sparse-data" aria-label="Permalink to &quot;How to handle sparse data&quot;">​</a></h3><p><strong>Option S-A — Optional fields throughout.</strong> Schema marks every flight-param field as optional. Missing = unknown; UI renders &quot;—&quot;. Simplest. Risks ambiguity: is <code>c3_km2_s2: undefined</code> because we don&#39;t know, or because we forgot to fill it?</p><p><strong>Option S-B — Explicit <code>unknown</code> tag.</strong> Each flight param has the form <code>{ value: number | null, source: string | null, confidence: &#39;measured&#39; | &#39;reconstructed&#39; | &#39;estimated&#39; | &#39;unknown&#39; }</code>. Verbose but unambiguous. Doubles the size of every numeric field.</p><p><strong>Option S-C — Top-level <code>flight_data_quality</code> flag + optional fields.</strong> One per-mission flag (<code>&#39;measured&#39; | &#39;reconstructed&#39; | &#39;sparse&#39; | &#39;unknown&#39;</code>) gates how we render <em>missing</em> fields. Optional fields elsewhere. UI can say &quot;Mariner 4 reconstructed flight data — some values approximate&quot; once at the top of the panel rather than per-field. Compact and honest.</p><h3 id="where-to-surface" tabindex="-1">Where to surface <a class="header-anchor" href="#where-to-surface" aria-label="Permalink to &quot;Where to surface&quot;">​</a></h3><p><strong>Option U-A — <code>/missions</code> FLIGHT tab + <code>/fly</code> HUD only.</strong> Timeline navigator deferred. Smallest scope; ships flight realism without UI invention.</p><p><strong>Option U-B — All three (FLIGHT tab + /fly HUD + timeline navigator).</strong> Complete experience. Timeline navigator is its own UX research surface.</p><p><strong>Option U-C — FLIGHT tab + /fly HUD now, timeline navigator as a v0.1.8 follow-up.</strong> Stage the work. Timeline navigator gets its own UXS spec + dedicated implementation slice once the flight-data foundation is solid.</p><h3 id="timeline-navigator-visual-approach" tabindex="-1">Timeline navigator visual approach <a class="header-anchor" href="#timeline-navigator-visual-approach" aria-label="Permalink to &quot;Timeline navigator visual approach&quot;">​</a></h3><p><strong>Option N-A — Horizontal strip with mission dots.</strong> 1957 → 2030 fixed range. Missions plotted as agency-coloured dots at their launch year. Drag a window-of-interest range; cards below filter to the windowed missions. Pinch-to-zoom on mobile. ~80 px tall.</p><p><strong>Option N-B — Vertical timeline with annotated decades.</strong> Decade markers on the left, missions clustered by year. More space-consuming; reads like a textbook. Better on tablets, awkward on phones.</p><p><strong>Option N-C — Hybrid: horizontal dot strip on phones, decade-annotated horizontal axis on desktop.</strong> Mobile-first per ADR-018. The desktop variant adds decade labels above the strip + agency legend in the right margin.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><p><strong>OQ #1 — How precise must <code>c3_km2_s2</code> be?</strong> Public records vary by source (NASA press kit vs JPL technical report vs reconstructed). Lock the policy: cite-the-most-authoritative-source-available; record the source string; round to one decimal place.</p></li><li><p><strong>OQ #2 — Do <code>events[]</code> carry editorial notes in the base file or the i18n overlay?</strong> Per ADR-017, editorial = overlay. So <code>events[].met_days</code> + <code>events[].type</code> are base-file (numeric/enum). The human-readable note lives in <code>data/i18n/[locale]/missions/[dest]/[id].json</code> under <code>events[]</code>. Already partly the convention.</p></li><li><p><strong>OQ #3 — Backward compatibility for the existing <code>delta_v</code> string.</strong> Two paths: (A) keep <code>delta_v</code> as a presentation string; the new <code>total_dv_km_s: number</code> is what <code>/fly</code> consumes. (B) deprecate <code>delta_v</code> and migrate. Path A wins on minimal disruption; Path B wins on no-two-sources-of-truth. Pick A for the slice; flag B for a follow-up.</p></li><li><p><strong>OQ #4 — Timeline navigator on <code>/missions/:id</code> deep-links?</strong> When a user shares <code>/missions?mission=curiosity</code>, does the timeline jump to 2011 and show Curiosity highlighted? Probably yes — coherent with ADR-024. Tracked here for closure.</p></li><li><p><strong>OQ #5 — Performance budget for timeline scrubbing.</strong> 28 missions today; 100+ in the long run. Re-rendering 100 cards on every scrub frame is too much. Need a debounce / virtualisation pattern. Defer the constraint to ADR-027&#39;s implementation notes.</p></li></ol><h2 id="goals-for-the-closure-adr-adr-027" tabindex="-1">Goals for the closure ADR (ADR-027) <a class="header-anchor" href="#goals-for-the-closure-adr-adr-027" aria-label="Permalink to &quot;Goals for the closure ADR (ADR-027)&quot;">​</a></h2><p>The ADR locks:</p><ul><li>The schema additions to <code>mission.schema.json</code> (and any new sub-schema files)</li><li>The data-quality / unknown-handling convention</li><li>The list of params required vs optional</li><li>The order of surface rollout (FLIGHT tab → /fly HUD → timeline navigator)</li><li>The timeline navigator&#39;s mobile + desktop layout</li><li>The migration plan for the existing 28 missions (which gets full flight params first; which stays partial)</li><li>The i18n overlay convention for events[] notes</li></ul>',33)])])}const p=o(s,[["render",n]]);export{m as __pageData,p as default};
